                    <p className="text-[9px] text-muted-foreground">{selectedIndustrySlug === 'bakery' ? 'Orders' : selectedIndustrySlug === 'events' ? 'Events' : selectedIndustrySlug === 'retail' ? 'Sales' : 'Bookings'}</p>
