// --- Generic CRUD Helper ---
function CrudPage({ title, description, icon: Icon, endpoint, columns, fields, defaultForm, successMsg }: any) {
  const { currentTenant, currency } = useAppStore() as any;
  const [items, setItems] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState<any>(null);
  const [form, setForm] = useState(defaultForm);
  const tid = currentTenant?.id;

  const load = useCallback(() => {
    if (!tid) return;
    authFetch(`/api/tenant/${tid}/${endpoint}`).then(r => r.json()).then(d => { setItems(Array.isArray(d) ? d : []); setLoading(false); }).catch(() => setLoading(false));
  }, [tid, endpoint]);
  useEffect(() => { load(); }, [load]);

  const openCreate = () => { setEditing(null); setForm(defaultForm); setShowForm(true); };
  const openEdit = (row: any) => { setEditing(row); setForm(row); setShowForm(true); };
  const handleSave = async () => {
    const isEdit = !!editing?.id;
    await authFetch(`/api/tenant/${tid}/${endpoint}`, { method: isEdit ? 'PUT' : 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(isEdit ? { id: editing.id, ...form } : form) });
    setShowForm(false); setEditing(null); setForm(defaultForm); load(); toast.success(successMsg || (isEdit ? 'Updated!' : 'Created!'));
  };
  const handleDelete = async (row: any) => {
    await authFetch(`/api/tenant/${tid}/${endpoint}`, { method: 'DELETE', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: row.id }) });
    load(); toast.success('Deleted!');
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div><h1 className="text-2xl font-bold">{title}</h1><p className="text-sm text-muted-foreground">{description}</p></div>
        <Button onClick={openCreate} className="bg-gradient-to-r from-blue-700 to-blue-500"><Plus className="w-4 h-4 mr-2" />Add New</Button>
      </div>
      {loading ? <PageSkeleton type="table" /> : items.length === 0 ? (
        <EmptyState icon={Icon} title={`No ${title.toLowerCase()} yet`} description={`Start by adding your first entry`} action={`Add ${title}`} onAction={openCreate} />
      ) : <DataGrid data={items} columns={columns} onEdit={openEdit} onDelete={handleDelete} />}
      <Dialog open={showForm} onOpenChange={setShowForm}>
        <DialogContent className="max-w-lg max-h-[85vh] overflow-y-auto">
          <DialogHeader><DialogTitle>{editing ? `Edit ${title}` : `Add ${title}`}</DialogTitle></DialogHeader>
          <div className="space-y-4 mt-4">
            {fields.map((f: any) => (
              <div key={f.key}>
                <Label>{f.label}</Label>
                {f.type === 'select' ? (
                  <Select value={form[f.key] || ''} onValueChange={v => setForm((p: any) => ({ ...p, [f.key]: v }))}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>{f.options.map((o: any) => <SelectItem key={o.value || o} value={o.value || o}>{o.label || o}</SelectItem>)}</SelectContent>
                  </Select>
                ) : f.type === 'textarea' ? (
                  <Textarea value={form[f.key] || ''} onChange={e => setForm((p: any) => ({ ...p, [f.key]: e.target.value }))} rows={3} />
                ) : (
                  <Input type={f.type || 'text'} value={form[f.key] ?? (f.type === 'number' ? 0 : '')} onChange={e => setForm((p: any) => ({ ...p, [f.key]: f.type === 'number' ? parseFloat(e.target.value) || 0 : e.target.value }))} />
                )}
              </div>
            ))}
            <Button onClick={handleSave} className="w-full bg-gradient-to-r from-blue-700 to-blue-500">{editing ? 'Save Changes' : `Add ${title}`}</Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

