// --- Professional Pages ---
function TenantProjectsPage() {
  const { currentTenant, currency } = useAppStore() as any;
  const [items, setItems] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState<'kanban' | 'list'>('kanban');
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState<any>(null);
  const [form, setForm] = useState({ name: '', clientName: '', status: 'active', startDate: '', deadline: '', budget: 0, spent: 0, progress: 0, description: '' });
  const tid = currentTenant?.id;

  const load = useCallback(() => {
    if (!tid) return;
    authFetch(`/api/tenant/${tid}/projects`).then(r => r.json()).then(d => { setItems(Array.isArray(d) ? d : []); setLoading(false); }).catch(() => setLoading(false));
  }, [tid]);
  useEffect(() => { load(); }, [load]);

  const openCreate = () => { setEditing(null); setForm({ name: '', clientName: '', status: 'active', startDate: '', deadline: '', budget: 0, spent: 0, progress: 0, description: '' }); setShowForm(true); };
  const openEdit = (row: any) => { setEditing(row); setForm({ name: row.name || '', clientName: row.clientName || '', status: row.status || 'active', startDate: row.startDate ? new Date(row.startDate).toISOString().slice(0, 10) : '', deadline: row.deadline ? new Date(row.deadline).toISOString().slice(0, 10) : '', budget: row.budget || 0, spent: row.spent || 0, progress: row.progress || 0, description: row.description || '' }); setShowForm(true); };
  const handleSave = async () => {
    const isEdit = !!editing?.id;
    await authFetch(`/api/tenant/${tid}/projects`, { method: isEdit ? 'PUT' : 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(isEdit ? { id: editing.id, ...form } : form) });
    setShowForm(false); load(); toast.success(isEdit ? '¡Proyecto actualizado!' : '¡Proyecto creado!');
  };
  const handleDelete = async (row: any) => {
    await authFetch(`/api/tenant/${tid}/projects`, { method: 'DELETE', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: row.id }) });
    load(); toast.success('¡Proyecto eliminado!');
  };

  const columns: { key: string; label: string; color: string; bg: string; border: string }[] = [
    { key: 'active', label: 'En Progreso', color: 'text-blue-600', bg: 'bg-blue-500/10', border: 'border-blue-500/30' },
    { key: 'on_hold', label: 'En Espera', color: 'text-amber-600', bg: 'bg-amber-500/10', border: 'border-amber-500/30' },
    { key: 'completed', label: 'Completado', color: 'text-green-600', bg: 'bg-green-500/10', border: 'border-green-500/30' },
    { key: 'cancelled', label: 'Cancelado', color: 'text-red-600', bg: 'bg-red-500/10', border: 'border-red-500/30' },
  ];

  const totalBudget = items.reduce((s: number, p: any) => s + (p.budget || 0), 0);
  const totalSpent = items.reduce((s: number, p: any) => s + (p.spent || 0), 0);
  const activeCount = items.filter((p: any) => p.status === 'active').length;

  const isNearDeadline = (d: string) => {
    if (!d) return false;
    const diff = (new Date(d).getTime() - Date.now()) / (1000 * 60 * 60 * 24);
    return diff >= 0 && diff <= 7;
  };
  const isOverBudget = (budget: number, spent: number) => budget > 0 && spent > budget;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div><h1 className="text-2xl font-bold">Proyectos</h1><p className="text-sm text-muted-foreground">Gestionar proyectos de clientes</p></div>
        <div className="flex gap-2">
          <div className="flex border rounded-lg overflow-hidden">
            <Button variant={view === 'kanban' ? 'default' : 'ghost'} size="sm" onClick={() => setView('kanban')} className="text-xs rounded-none">Tablero</Button>
            <Button variant={view === 'list' ? 'default' : 'ghost'} size="sm" onClick={() => setView('list')} className="text-xs rounded-none">Lista</Button>
          </div>
          <Button onClick={openCreate} className="bg-gradient-to-r from-blue-700 to-blue-500"><Plus className="w-4 h-4 mr-2" />Nuevo Proyecto</Button>
        </div>
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card className="p-4"><p className="text-xs text-muted-foreground">Total Proyectos</p><p className="text-2xl font-bold">{items.length}</p></Card>
        <Card className="p-4"><p className="text-xs text-muted-foreground">En Progreso</p><p className="text-2xl font-bold text-blue-600">{activeCount}</p></Card>
        <Card className="p-4"><p className="text-xs text-muted-foreground">Presupuesto Total</p><p className="text-2xl font-bold">{formatCurrency(totalBudget, currency)}</p></Card>
        <Card className="p-4"><p className="text-xs text-muted-foreground">Total Gastado</p><p className={`text-2xl font-bold ${totalSpent > totalBudget && totalBudget > 0 ? 'text-red-600' : ''}`}>{formatCurrency(totalSpent, currency)}</p></Card>
      </div>

      {loading ? <PageSkeleton type="table" /> : items.length === 0 ? (
        <EmptyState icon={Briefcase} title="Sin proyectos" description="Crea tu primer proyecto" action="Nuevo Proyecto" onAction={openCreate} />
      ) : view === 'kanban' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
          {columns.map(col => {
            const colItems = items.filter((p: any) => p.status === col.key);
            return (
              <div key={col.key} className={`rounded-xl border ${col.border} bg-card`}>
                <div className={`flex items-center justify-between px-4 py-3 ${col.bg} rounded-t-xl`}>
                  <h3 className={`text-sm font-semibold ${col.color}`}>{col.label}</h3>
                  <Badge variant="outline" className="text-xs">{colItems.length}</Badge>
                </div>
                <div className="p-3 space-y-3 max-h-[60vh] overflow-y-auto">
                  {colItems.length === 0 && <p className="text-xs text-muted-foreground text-center py-4">Sin proyectos</p>}
                  {colItems.map((project: any) => {
                    const overBudget = isOverBudget(project.budget, project.spent);
                    const nearDeadline = isNearDeadline(project.deadline);
                    const budgetPct = project.budget > 0 ? Math.min(100, ((project.spent || 0) / project.budget) * 100) : 0;
                    return (
                      <motion.div key={project.id} layout className={`p-3 rounded-lg border hover:shadow-md transition-all ${nearDeadline ? 'border-amber-400' : ''} ${overBudget ? 'border-red-400' : ''}`}>
                        <div className="flex items-start justify-between gap-2">
                          <div className="flex-1 min-w-0">
                            <p className="font-semibold text-sm truncate">{project.name}</p>
                            <p className="text-xs text-muted-foreground mt-0.5">{project.clientName || 'Sin cliente'}</p>
                          </div>
                          <div className="flex gap-0.5 shrink-0">
                            <Button variant="ghost" size="icon" className="w-6 h-6" onClick={() => openEdit(project)}><Edit className="w-3 h-3" /></Button>
                            <Button variant="ghost" size="icon" className="w-6 h-6 text-destructive" onClick={() => handleDelete(project)}><Trash2 className="w-3 h-3" /></Button>
                          </div>
                        </div>
                        {project.deadline && <p className={`text-[10px] mt-1 ${nearDeadline ? 'text-amber-600 font-medium' : 'text-muted-foreground'}`}>{nearDeadline && <AlertTriangle className="w-3 h-3 inline mr-1" />}Fecha límite: {new Date(project.deadline).toLocaleDateString('es')}</p>}
                        {(project.spent > 0 || project.budget > 0) && (
                          <div className="mt-2">
                            <div className="flex justify-between text-[10px] text-muted-foreground mb-1">
                              <span>{project.spent > 0 ? `Gastado: ${formatCurrency(project.spent, currency)}` : `Progreso: ${project.progress}%`}</span>
                              {project.budget > 0 && <span>de {formatCurrency(project.budget, currency)}</span>}
                            </div>
                            <Progress value={project.spent > 0 ? budgetPct : project.progress} className={`h-1.5 ${overBudget ? '[&>div]:bg-red-500' : ''}`} />
                          </div>
                        )}
                      </motion.div>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="border rounded-xl overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead><tr className="bg-muted/50 border-b">
                <th className="text-left p-3 font-medium">Proyecto</th>
                <th className="text-left p-3 font-medium">Cliente</th>
                <th className="text-left p-3 font-medium">Estado</th>
                <th className="text-left p-3 font-medium">Inicio</th>
                <th className="text-left p-3 font-medium">Fecha Límite</th>
                <th className="text-right p-3 font-medium">Presupuesto</th>
                <th className="text-right p-3 font-medium">Gastado</th>
                <th className="text-center p-3 font-medium">Progreso</th>
                <th className="text-right p-3 font-medium">Acciones</th>
              </tr></thead>
              <tbody>
                {items.map((p: any) => (
                  <tr key={p.id} className="border-b hover:bg-muted/30 transition-colors">
                    <td className="p-3 font-medium">{p.name}</td>
                    <td className="p-3 text-muted-foreground">{p.clientName || '—'}</td>
                    <td className="p-3"><Badge variant="outline" className="text-xs">{columns.find(c => c.key === p.status)?.label || p.status}</Badge></td>
                    <td className="p-3 text-muted-foreground">{p.startDate ? new Date(p.startDate).toLocaleDateString('es') : '—'}</td>
                    <td className={`p-3 ${isNearDeadline(p.deadline) ? 'text-amber-600 font-medium' : 'text-muted-foreground'}`}>{p.deadline ? new Date(p.deadline).toLocaleDateString('es') : '—'}</td>
                    <td className="p-3 text-right">{formatCurrency(p.budget || 0, currency)}</td>
                    <td className={`p-3 text-right ${isOverBudget(p.budget, p.spent) ? 'text-red-600 font-medium' : ''}`}>{formatCurrency(p.spent || 0, currency)}</td>
                    <td className="p-3"><div className="flex items-center gap-2"><Progress value={p.progress || 0} className="w-16 h-2" /><span className="text-xs">{p.progress || 0}%</span></div></td>
                    <td className="p-3 text-right">
                      <div className="flex justify-end gap-1">
                        <Button variant="ghost" size="icon" className="w-7 h-7" onClick={() => openEdit(p)}><Edit className="w-3 h-3" /></Button>
                        <Button variant="ghost" size="icon" className="w-7 h-7 text-destructive" onClick={() => handleDelete(p)}><Trash2 className="w-3 h-3" /></Button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      <Dialog open={showForm} onOpenChange={setShowForm}>
        <DialogContent className="max-w-lg max-h-[85vh] overflow-y-auto">
          <DialogHeader><DialogTitle>{editing ? 'Editar Proyecto' : 'Nuevo Proyecto'}</DialogTitle></DialogHeader>
          <div className="space-y-4 mt-4">
            <div><Label>Nombre del Proyecto *</Label><Input value={form.name} onChange={e => setForm(p => ({ ...p, name: e.target.value }))} /></div>
            <div><Label>Cliente</Label><Input value={form.clientName} onChange={e => setForm(p => ({ ...p, clientName: e.target.value }))} /></div>
            <div><Label>Estado</Label><Select value={form.status} onValueChange={v => setForm(p => ({ ...p, status: v }))}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>
                <SelectItem value="active">En Progreso</SelectItem>
                <SelectItem value="on_hold">En Espera</SelectItem>
                <SelectItem value="completed">Completado</SelectItem>
                <SelectItem value="cancelled">Cancelado</SelectItem>
              </SelectContent>
            </Select></div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Fecha de Inicio</Label><Input type="date" value={form.startDate} onChange={e => setForm(p => ({ ...p, startDate: e.target.value }))} /></div>
              <div><Label>Fecha Límite</Label><Input type="date" value={form.deadline} onChange={e => setForm(p => ({ ...p, deadline: e.target.value }))} /></div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>Presupuesto</Label><Input type="number" value={form.budget || ''} onChange={e => setForm(p => ({ ...p, budget: parseFloat(e.target.value) || 0 }))} /></div>
              <div><Label>Gastado</Label><Input type="number" value={form.spent || ''} onChange={e => setForm(p => ({ ...p, spent: parseFloat(e.target.value) || 0 }))} /></div>
            </div>
            <div>
              <Label>Progreso ({form.progress}%)</Label>
              <Input type="range" min={0} max={100} value={form.progress} onChange={e => setForm(p => ({ ...p, progress: parseInt(e.target.value) || 0 }))} className="mt-1" />
            </div>
            <div><Label>Descripción</Label><Textarea value={form.description} onChange={e => setForm(p => ({ ...p, description: e.target.value }))} /></div>
            <Button onClick={handleSave} disabled={!form.name} className="w-full bg-gradient-to-r from-blue-700 to-blue-500">{editing ? 'Guardar Cambios' : 'Crear Proyecto'}</Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function TenantTimeTrackingPage() {
  const { currency } = useAppStore() as any;
  const cols = [
    { key: 'description', label: 'Description', render: (v: string) => <span className="font-medium">{v}</span> },
    { key: 'duration', label: 'Hours', render: (v: number) => `${(v / 60).toFixed(1)}h` },
    { key: 'billingRate', label: 'Rate', render: (v: number) => formatCurrency(v, currency) },
    { key: 'amount', label: 'Amount', render: (v: number, row: any) => formatCurrency(row.billingRate * row.duration / 60, currency) },
    { key: 'billable', label: 'Billable', render: (v: boolean) => <Badge variant={v ? 'default' : 'secondary'}>{v ? 'Yes' : 'No'}</Badge> },
    { key: 'date', label: 'Date', render: (v: string) => v ? new Date(v).toLocaleDateString() : '—' },
  ];
  const fields = [
    { key: 'description', label: 'Description *' },
    { key: 'duration', label: 'Duration (minutes)', type: 'number' },
    { key: 'billingRate', label: 'Billing Rate', type: 'number' },
    { key: 'billable', label: 'Billable', type: 'select', options: [{ value: 'true', label: 'Yes' }, { value: 'false', label: 'No' }] },
    { key: 'date', label: 'Date', type: 'date' },
  ];
  return <CrudPage title="Time Tracking" description="Track billable hours" icon={Clock} endpoint="time-entries" columns={cols} fields={fields} defaultForm={{ description: '', duration: 60, billingRate: 0, billable: true, date: new Date().toISOString().slice(0, 10) }} successMsg="Time entry saved!" />;
}

function TenantContractsPage() {
  const { currency } = useAppStore() as any;
  const cols = [
    { key: 'clientName', label: 'Client', render: (v: string) => <span className="font-medium">{v || '—'}</span> },
    { key: 'type', label: 'Type', render: (v: string) => v ? <Badge variant="secondary">{v}</Badge> : '—' },
    { key: 'value', label: 'Value', render: (v: number) => formatCurrency(v, currency) },
    { key: 'startDate', label: 'Start', render: (v: string) => v ? new Date(v).toLocaleDateString() : '—' },
    { key: 'endDate', label: 'End', render: (v: string) => v ? new Date(v).toLocaleDateString() : '—' },
    { key: 'status', label: 'Status', render: (v: string) => <Badge variant={v === 'active' ? 'default' : v === 'expired' ? 'destructive' : 'secondary'}>{v}</Badge> },
  ];
  const fields = [
    { key: 'clientName', label: 'Client Name *' },
    { key: 'type', label: 'Contract Type', type: 'select', options: ['Fixed Price', 'Retainer', 'Time & Materials', 'Consulting', 'SLA', 'Other'] },
    { key: 'value', label: 'Contract Value', type: 'number' },
    { key: 'startDate', label: 'Start Date', type: 'date' },
    { key: 'endDate', label: 'End Date', type: 'date' },
    { key: 'status', label: 'Status', type: 'select', options: [{ value: 'active', label: 'Active' }, { value: 'draft', label: 'Draft' }, { value: 'expired', label: 'Expired' }, { value: 'terminated', label: 'Terminated' }] },
    { key: 'description', label: 'Description', type: 'textarea' },
  ];
  return <CrudPage title="Contracts" description="Manage client contracts" icon={ScrollText} endpoint="contracts" columns={cols} fields={fields} defaultForm={{ clientName: '', type: '', value: 0, startDate: '', endDate: '', status: 'draft', description: '' }} successMsg="Contract saved!" />;
}

// ============ TENANT CATALOG PAGE (REAL) ============
function TenantCatalogPage() {
  const { currentTenant, currency } = useAppStore() as any;
  const [items, setItems] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState('all');
  const [showCreate, setShowCreate] = useState(false);
  const tenantId = currentTenant?.id;
  const load = useCallback(() => { if (tenantId) { authFetch(`/api/tenant/${tenantId}/catalog`).then(r => r.json()).then(d => { setItems(Array.isArray(d) ? d : []); setLoading(false); }).catch(() => setLoading(false)); } }, [tenantId]);
  useEffect(() => { load(); }, [load]);
  const categories = ['all', ...Array.from(new Set(items.map((i: any) => i.category).filter(Boolean)))];
  const filtered = items.filter((i: any) => { if (catFilter !== 'all' && i.category !== catFilter) return false; if (search && !i.name?.toLowerCase().includes(search.toLowerCase())) return false; return true; });
  const [form, setForm] = useState({ name: '', description: '', category: 'Panaderia', price: 0, cost: 0, unit: 'unidad', isAvailable: true });
  const handleCreate = async () => {
    try { await authFetch(`/api/tenant/${currentTenant.id}/catalog`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(form) }); setShowCreate(false); setForm({ name: '', description: '', category: 'Panaderia', price: 0, cost: 0, unit: 'unidad', isAvailable: true }); load(); toast.success('Producto creado!'); } catch { toast.error('Error'); }
  };
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div><h1 className="text-2xl font-bold">Products &amp; Menu</h1><p className="text-sm text-muted-foreground">Gestiona tu catalogo de productos</p></div>
        <Button onClick={() => setShowCreate(true)} className="bg-gradient-to-r from-blue-700 to-blue-500"><Plus className="w-4 h-4 mr-2" />Nuevo Producto</Button>
      </div>
      <div className="flex gap-3 flex-wrap"><Input placeholder="Buscar producto..." value={search} onChange={e => setSearch(e.target.value)} className="max-w-xs" /><Select value={catFilter} onValueChange={setCatFilter}>{categories.map(c => <SelectItem key={c} value={c}>{c === 'all' ? 'Todas' : c}</SelectItem>)}</Select></div>
      {loading ? <div className="flex items-center justify-center py-20"><Loader2 className="w-8 h-8 animate-spin text-muted-foreground" /></div> : filtered.length === 0 ? <Card className="p-12 text-center"><Package className="w-12 h-12 mx-auto mb-4 text-muted-foreground" /><p className="text-muted-foreground">No hay productos. Crea tu primer producto.</p></Card> : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filtered.map((item: any) => <Card key={item.id} className="p-4 hover:shadow-md transition-shadow"><div className="flex justify-between items-start"><div><h3 className="font-semibold">{item.name}</h3><p className="text-xs text-muted-foreground mt-1">{item.category}</p></div><Badge variant={item.isAvailable !== false ? 'outline' : 'secondary'} className={item.isAvailable !== false ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : ''}>{item.isAvailable !== false ? 'Activo' : 'Inactivo'}</Badge></div>{item.description && <p className="text-sm text-muted-foreground mt-2 line-clamp-2">{item.description}</p>}<div className="flex justify-between items-center mt-3 pt-3 border-t"><span className="text-lg font-bold text-blue-600">{currency || 'TTD'} {(item.price || 0).toFixed(2)}</span><span className="text-xs text-muted-foreground">Costo: {currency || 'TTD'} {(item.cost || 0).toFixed(2)}</span></div></Card>)}
        </div>
      )}
      <Dialog open={showCreate} onOpenChange={setShowCreate}><DialogContent className="max-w-md"><DialogHeader><DialogTitle>Nuevo Producto</DialogTitle></DialogHeader><div className="space-y-4 mt-2"><div><Label>Nombre *</Label><Input value={form.name} onChange={e => setForm(p => ({ ...p, name: e.target.value }))} /></div><div><Label>Categoria</Label><Input value={form.category} onChange={e => setForm(p => ({ ...p, category: e.target.value }))} /></div><div className="grid grid-cols-2 gap-4"><div><Label>Precio *</Label><Input type="number" value={form.price || ''} onChange={e => setForm(p => ({ ...p, price: Number(e.target.value) }))} /></div><div><Label>Costo</Label><Input type="number" value={form.cost || ''} onChange={e => setForm(p => ({ ...p, cost: Number(e.target.value) }))} /></div></div><div><Label>Descripcion</Label><Textarea value={form.description} onChange={e => setForm(p => ({ ...p, description: e.target.value }))} /></div><div className="flex items-center gap-2"><Checkbox checked={form.isAvailable} onCheckedChange={v => setForm(p => ({ ...p, isAvailable: v }))} /><Label>Disponible</Label></div></div><DialogFooter><Button onClick={handleCreate} className="bg-blue-600 hover:bg-blue-700">Crear Producto</Button></DialogFooter></DialogContent></Dialog>
    </div>
  );
}

// ============ TENANT INGREDIENTS PAGE (REAL) ============
function TenantIngredientsPage() {
  const { currentTenant, currency } = useAppStore() as any;
  const [ingredients, setIngredients] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [showCreate, setShowCreate] = useState(false);
  const tenantId = currentTenant?.id;
  const load = useCallback(() => { if (tenantId) { authFetch(`/api/tenant/${tenantId}/ingredients`).then(r => r.json()).then(d => { setIngredients(Array.isArray(d) ? d : []); setLoading(false); }).catch(() => setLoading(false)); } }, [tenantId]);
  useEffect(() => { load(); }, [load]);
  const filtered = ingredients.filter((i: any) => !search || i.name?.toLowerCase().includes(search.toLowerCase()) || i.category?.toLowerCase().includes(search.toLowerCase()));
  const lowStockItems = filtered.filter((i: any) => i.minStock > 0 && i.quantity <= i.minStock);
  const [form, setForm] = useState({ name: '', category: 'Harinas', unit: 'kg', costPerUnit: 0, quantity: 0, minStock: 0, supplier: '' });
  const handleCreate = async () => {
    try { await authFetch(`/api/tenant/${currentTenant.id}/ingredients`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(form) }); setShowCreate(false); setForm({ name: '', category: 'Harinas', unit: 'kg', costPerUnit: 0, quantity: 0, minStock: 0, supplier: '' }); load(); toast.success('Ingrediente agregado!'); } catch { toast.error('Error'); }
  };
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div><h1 className="text-2xl font-bold">Ingredientes</h1><p className="text-sm text-muted-foreground">Inventario de materias primas</p></div>
        <Button onClick={() => setShowCreate(true)} className="bg-gradient-to-r from-blue-700 to-blue-500"><Plus className="w-4 h-4 mr-2" />Nuevo Ingrediente</Button>
      </div>
      {lowStockItems.length > 0 && <Card className="p-4 border-amber-300 bg-amber-50 dark:bg-amber-900/20"><div className="flex items-center gap-2 text-amber-700 dark:text-amber-400 font-medium"><AlertTriangle className="w-4 h-4" />Stock Bajo ({lowStockItems.length} items)</div><div className="flex gap-2 mt-2 flex-wrap">{lowStockItems.map((i: any) => <Badge key={i.id} variant="outline" className="bg-amber-100 border-amber-300">{i.name}: {i.quantity} {i.unit}</Badge>)}</div></Card>}
      <Input placeholder="Buscar ingrediente..." value={search} onChange={e => setSearch(e.target.value)} className="max-w-xs" />
      {loading ? <div className="flex items-center justify-center py-20"><Loader2 className="w-8 h-8 animate-spin text-muted-foreground" /></div> : filtered.length === 0 ? <Card className="p-12 text-center"><Package className="w-12 h-12 mx-auto mb-4 text-muted-foreground" /><p className="text-muted-foreground">No hay ingredientes registrados.</p></Card> : (
        <Card><Table><TableHeader><TableRow><TableHead>Nombre</TableHead><TableHead>Categoria</TableHead><TableHead>Cantidad</TableHead><TableHead>Unidad</TableHead><TableHead>Costo Unit.</TableHead><TableHead>Min. Stock</TableHead><TableHead>Proveedor</TableHead></TableRow></TableHeader><TableBody>{filtered.map((i: any) => <TableRow key={i.id}><TableCell className="font-medium">{i.name}</TableCell><TableCell><Badge variant="outline">{i.category}</Badge></TableCell><TableCell>{i.minStock > 0 && i.quantity <= i.minStock ? <span className="text-red-600 font-semibold">{i.quantity || 0}</span> : <span>{i.quantity || 0}</span>}</TableCell><TableCell>{i.unit}</TableCell><TableCell>{currency || 'TTD'} {(i.costPerUnit || 0).toFixed(2)}</TableCell><TableCell>{i.minStock || '-'}</TableCell><TableCell className="text-sm text-muted-foreground">{i.supplier || '-'}</TableCell></TableRow>)}</TableBody></Table></Card>
      )}
      <Dialog open={showCreate} onOpenChange={setShowCreate}><DialogContent className="max-w-md"><DialogHeader><DialogTitle>Nuevo Ingrediente</DialogTitle></DialogHeader><div className="space-y-4 mt-2"><div><Label>Nombre *</Label><Input value={form.name} onChange={e => setForm(p => ({ ...p, name: e.target.value }))} /></div><div className="grid grid-cols-2 gap-4"><div><Label>Categoria</Label><Input value={form.category} onChange={e => setForm(p => ({ ...p, category: e.target.value }))} /></div><div><Label>Unidad</Label><Input value={form.unit} onChange={e => setForm(p => ({ ...p, unit: e.target.value }))} /></div></div><div className="grid grid-cols-3 gap-4"><div><Label>Cantidad</Label><Input type="number" value={form.quantity || ''} onChange={e => setForm(p => ({ ...p, quantity: Number(e.target.value) }))} /></div><div><Label>Costo Unit.</Label><Input type="number" value={form.costPerUnit || ''} onChange={e => setForm(p => ({ ...p, costPerUnit: Number(e.target.value) }))} /></div><div><Label>Min. Stock</Label><Input type="number" value={form.minStock || ''} onChange={e => setForm(p => ({ ...p, minStock: Number(e.target.value) }))} /></div></div><div><Label>Proveedor</Label><Input value={form.supplier} onChange={e => setForm(p => ({ ...p, supplier: e.target.value }))} /></div></div><DialogFooter><Button onClick={handleCreate} className="bg-blue-600 hover:bg-blue-700">Agregar</Button></DialogFooter></DialogContent></Dialog>
    </div>
  );
}

