// ============ CT ERROR + LOADING HELPERS ============
function CTErrorDisplay({ error, onRetry }: { error: string; onRetry: () => void }) {
  const locale = useAppStore(s => s.locale);
  const isAuthError = error?.toLowerCase().includes('token') || error?.toLowerCase().includes('auth') || error?.toLowerCase().includes('session') || error?.toLowerCase().includes('expired') || error?.toLowerCase().includes('login');
  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex flex-col items-center justify-center py-16 space-y-4">
      <div className={`w-16 h-16 rounded-full flex items-center justify-center ${isAuthError ? 'bg-amber-100 dark:bg-amber-900/30' : 'bg-red-100 dark:bg-red-900/30'}`}>
        {isAuthError ? <KeyRound className="w-8 h-8 text-amber-500" /> : <AlertTriangle className="w-8 h-8 text-red-500" />}
      </div>
      <div className="text-center space-y-2">
        <h3 className={`text-lg font-semibold ${isAuthError ? 'text-amber-600 dark:text-amber-400' : 'text-red-600 dark:text-red-400'}`}>
          {isAuthError ? t('error.sessionExpired', locale) : t('error.loadingData', locale)}
        </h3>
        <p className="text-sm text-muted-foreground max-w-md">{isAuthError ? t('error.sessionExpiredDesc', locale) : error}</p>
      </div>
      <div className="flex gap-3">
        {isAuthError ? (
          <Button onClick={() => useAppStore.getState().logout()} className="gap-2 bg-amber-600 hover:bg-amber-700 text-white">
            <LogIn className="w-4 h-4" /> {t('error.loginAgain', locale)}
          </Button>
        ) : (
          <Button variant="outline" onClick={onRetry} className="gap-2"><RefreshCw className="w-4 h-4" /> {t('error.tryAgain', locale)}</Button>
        )}
      </div>
    </motion.div>
  );
}

// ============ SKELETON LOADERS ============
function PageSkeleton({ type = 'list' }: { type?: 'stats' | 'list' | 'table' | 'dashboard' | 'cards' }) {
  if (type === 'stats') return (
    <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
      {[...Array(4)].map((_, i) => (
        <div key={i} className="bg-card border rounded-xl p-4 space-y-3">
          <div className="h-3 w-20 bg-muted animate-pulse rounded" />
          <div className="h-7 w-28 bg-muted animate-pulse rounded" />
          <div className="h-3 w-16 bg-muted animate-pulse rounded" />
        </div>
      ))}
    </div>
  );
  if (type === 'table') return (
    <div className="space-y-3">
      <div className="flex gap-4 mb-4"><div className="h-9 w-48 bg-muted animate-pulse rounded" /><div className="h-9 w-36 bg-muted animate-pulse rounded" /></div>
      <div className="bg-card border rounded-lg overflow-hidden">
        <div className="h-10 bg-muted/50 border-b" />
        {[...Array(5)].map((_, i) => <div key={i} className="flex items-center gap-4 px-4 py-3 border-b last:border-0"><div className="h-4 w-32 bg-muted animate-pulse rounded" /><div className="h-4 w-24 bg-muted animate-pulse rounded" /><div className="h-4 w-20 bg-muted animate-pulse rounded ml-auto" /></div>)}
      </div>
    </div>
  );
  if (type === 'dashboard') return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[...Array(4)].map((_, i) => (<div key={i} className="bg-card border rounded-xl p-4 space-y-3"><div className="h-3 w-24 bg-muted animate-pulse rounded" /><div className="h-7 w-32 bg-muted animate-pulse rounded" /></div>))}
      </div>
      <div className="grid md:grid-cols-2 gap-4">
        {[...Array(2)].map((_, i) => (<div key={i} className="bg-card border rounded-xl p-4 h-48"><div className="h-3 w-20 bg-muted animate-pulse rounded mb-4" /><div className="h-full w-full bg-muted/30 rounded animate-pulse" /></div>))}
      </div>
      <div className="bg-card border rounded-lg"><div className="h-10 bg-muted/50 border-b" />{[...Array(5)].map((_, i) => <div key={i} className="flex items-center gap-4 px-4 py-3 border-b last:border-0"><div className="h-4 w-36 bg-muted animate-pulse rounded" /><div className="h-4 w-20 bg-muted animate-pulse rounded" /><div className="h-4 w-16 bg-muted animate-pulse rounded ml-auto" /></div>)}</div>
    </div>
  );
  if (type === 'cards') return (
    <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
      {[...Array(6)].map((_, i) => (<div key={i} className="bg-card border rounded-xl p-5 space-y-3"><div className="h-5 w-36 bg-muted animate-pulse rounded" /><div className="h-3 w-full bg-muted animate-pulse rounded" /><div className="h-3 w-2/3 bg-muted animate-pulse rounded" /></div>))}
    </div>
  );
  // default: list
  return (
    <div className="space-y-3">
      {[...Array(6)].map((_, i) => (<div key={i} className="bg-card border rounded-lg px-4 py-3 flex items-center gap-4"><div className="h-10 w-10 bg-muted animate-pulse rounded-full" /><div className="flex-1 space-y-2"><div className="h-4 w-40 bg-muted animate-pulse rounded" /><div className="h-3 w-28 bg-muted animate-pulse rounded" /></div></div>))}
    </div>
  );
}

function CTLoading() {
  return <PageSkeleton type="dashboard" />;
}

// ============ MAIN APP ============

export default function ZBSApp() {
  const { view, portalPage, theme, tenantPage, setTenantPage, setShowFinancialReports, setUser, setCurrentTenant, setView, setToken } = useAppStore();
  const [restoring, setRestoring] = useState(true);

  // Session restore on mount — verify JWT token
  useEffect(() => {
    const savedToken = localStorage.getItem('zbs-token');
    if (!savedToken) { setRestoring(false); return; }
    // Safety timeout: never stay stuck on restoring for more than 5 seconds
    const safetyTimer = setTimeout(() => { setRestoring(false); }, 5000);
    (async () => {
      try {
        const res = await fetch('/api/auth/verify', {
          headers: { 'Authorization': `Bearer ${savedToken}`, 'Content-Type': 'application/json' }
        });
        const data = await res.json();
        if (res.ok && data.valid) {
          setToken(savedToken);
          setUser(data);
          if (data.tenant) setCurrentTenant(data.tenant);
          if (data.tenant?.status === 'pending_approval') {
            setView('pending_approval');
          } else if (data.isSuperAdmin) {
            setView('control_tower');
          } else {
            setView('tenant_app');
          }
        } else {
          // Token invalid/expired — clear it and let user log in fresh
          localStorage.removeItem('zbs-token');
          useAppStore.getState().setToken(null);
        }
      } catch {
        // Network error on verify — clear stale token to avoid auth loops
        localStorage.removeItem('zbs-token');
        useAppStore.getState().setToken(null);
      } finally { clearTimeout(safetyTimer); setRestoring(false); }
    })();
  }, [setUser, setCurrentTenant, setView, setToken]);

  // Keyboard shortcuts
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      // Ctrl+Shift+F: Toggle stealth finance
      if ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'F') {
        e.preventDefault();
        setShowFinancialReports(true);
        setTenantPage('stealth_finance');
      }
      // Ctrl+Shift+X: Global panic button — immediately hide all financial data
      if ((e.ctrlKey || e.metaKey) && e.shiftKey && (e.key === 'X' || e.key === 'x')) {
        e.preventDefault();
        const financialPages = ['stealth_finance', 'bookkeeping', 'expenses', 'reports', 'cost_analysis'];
        if (financialPages.includes(tenantPage)) {
          useAppStore.getState().setPanicMode(true);
          setTenantPage('dashboard');
        }
      }
      // Escape: Panic button for financial pages
      if (e.key === 'Escape') {
        const financialPages = ['stealth_finance', 'bookkeeping', 'expenses', 'reports', 'cost_analysis'];
        if (financialPages.includes(tenantPage)) {
          useAppStore.getState().setPanicMode(true);
          setTenantPage('dashboard');
        }
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [tenantPage, setTenantPage, setShowFinancialReports]);

  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else if (theme === 'light') root.classList.remove('dark');
    else {
      const mq = window.matchMedia('(prefers-color-scheme: dark)');
      root.classList.toggle('dark', mq.matches);
      const handler = (e: MediaQueryListEvent) => root.classList.toggle('dark', e.matches);
      mq.addEventListener('change', handler);
      return () => mq.removeEventListener('change', handler);
    }
  }, [theme]);

  // Track page visits for analytics
  useEffect(() => {
    const trackVisit = async () => {
      try {
        const page = view === 'portal' ? `portal/${portalPage}` : view;
        await authFetch('/api/platform/visitor-analytics', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            page,
            referrer: document.referrer || 'direct',
            userAgent: navigator.userAgent,
          }),
        });
      } catch {}
    };
    trackVisit();
  }, [view, portalPage]);

  if (restoring) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <TooltipProvider>
      <AnimatePresence mode="wait">
        {view === 'portal' && <PortalView key="portal" />}
        {view === 'login' && <LoginView key="login" />}
        {view === 'onboarding' && <OnboardingView key="onboarding" />}
        {view === 'pending_approval' && <PendingApprovalView key="pending" />}
        {view === 'control_tower' && <ControlTowerView key="ct" />}
        {view === 'tenant_app' && <TenantAppView key="tenant" />}
      </AnimatePresence>
    </TooltipProvider>
  );
}
